select te.id as entry_id, te.parent_id as entry_parent_id, te.material_id as entry_material_id, te.inventory_id as entry_inventory_id, te.material_name as entry_material_name, te.specification as entry_specification, te.model as entry_model, te.unit as entry_unit, te.quantity as entry_quantity, te.charge_price as entry_charge_price, te.batch_no as entry_batch_no, te.expiry_date as entry_expiry_date, te.master_barcode as entry_master_barcode, te.secondary_barcode as entry_secondary_barcode, te.in_hospital_code as entry_in_hospital_code, te.manufacturer as entry_manufacturer, te.supplier as entry_supplier, te.supplier_id as entry_supplier_id, te.certificate_no as entry_certificate_no, te.billing_follow as entry_billing_follow, te.del_flag as entry_del_flag, t.order_status as parent_order_status, t.patient_name, t.patient_sex, t.chief_surgeon, t.hospital_number as patient_hospital_number, t.visit_kind as visit_kind, ad.name as apply_dept_name, ed.name as exec_dept_name, wod.name as write_off_dept_name, t.admission_diagnosis as surgical_diagnosis, t.surgery_date as billing_time, t.create_by as scan_user, t.create_time as scan_date, m.id as mId, m.code as materialCode, m.name as materialName, m.speci as materialSpeci, m.model as materialModel, m.register_no as materialRegisterNo, m.period_date as materialPeriodDate, m.udi_no as materialUdiNo, m.medical_no as materialMedicalNo, m.is_billing as materialIsBilling, m.is_procure as materialIsProcure, m.is_monitor as materialIsMonitor, m.sunshine_code as materialSunshineCode, m.unit_id as materialUnitId, m.finance_category_id as materialFinanceCategoryId, m.storeroom_id as materialWarehouseCategoryId, m.his_charge_item_id, hci.item_code as his_charge_item_code, hci.item_name as his_charge_item_name, hci.spec_model as his_charge_item_speci, hci.price as his_charge_item_price, u.unit_id as uId, u.unit_name as unitName, f.factory_id as factoryId, f.factory_name as factoryName, fc.finance_category_id as fcId, fc.finance_category_name as financeCategoryName, wc.warehouse_category_id as wcId, wc.warehouse_category_name as warehouseCategoryName, coalesce(fs.name, te.supplier) as supplier_display_name, coalesce(hci.item_code, m.his_charge_item_id) as charge_code, gdi.material_date as begin_time, gdi.material_no as batch_number, gdi.material_date as material_date, gdi.material_no as material_no, coalesce(wh_src.name, gwf.warehouse_name) as warehouse_name, coalesce(gwf.bill_no, gwf.origin_business_type) as batch_source, gwf.origin_business_type as origin_business_type from gz_traceability_entry te left join gz_traceability t on te.parent_id = t.id left join fd_department ad on t.apply_dept_id = ad.id left join fd_department ed on t.exec_dept_id = ed.id left join fd_department wod on t.write_off_dept_id = wod.id left join fd_material m on te.material_id = m.id left join gz_dep_inventory gdi on te.inventory_id = gdi.id and gdi.del_flag != 1 left join fd_unit u on m.unit_id = u.unit_id left join fd_factory f on m.factory_id = f.factory_id left join fd_finance_category fc on m.finance_category_id = fc.finance_category_id left join fd_warehouse_category wc on m.storeroom_id = wc.warehouse_category_id left join fd_supplier fs on fs.id = coalesce(te.supplier_id, gdi.supplier_id) left join his_charge_item_mirror hci on hci.tenant_id = t.tenant_id and hci.charge_item_id = m.his_charge_item_id and (hci.deleted_flag is null or hci.deleted_flag != 1) left join gz_depot_inventory gdep on gdep.in_hospital_code = te.in_hospital_code and gdep.batch_no = te.batch_no and IFNULL(gdep.del_flag, 0) != 1 and gdep.tenant_id = t.tenant_id left join fd_warehouse wh_src on wh_src.id = gdep.warehouse_id left join ( select wf.in_hospital_code, wf.tenant_id, wf.warehouse_name, wf.origin_business_type, wf.bill_no from gz_wh_flow wf inner join ( select in_hospital_code, tenant_id, max(flow_time) as max_flow_time from gz_wh_flow where IFNULL(del_flag, 0) = 0 and lx = 'RK' group by in_hospital_code, tenant_id ) wfmax on wf.in_hospital_code = wfmax.in_hospital_code and wf.tenant_id = wfmax.tenant_id and wf.flow_time = wfmax.max_flow_time where IFNULL(wf.del_flag, 0) = 0 and wf.lx = 'RK' ) gwf on gwf.in_hospital_code = te.in_hospital_code and gwf.tenant_id = t.tenant_id where te.del_flag = '0' and t.del_flag = '0' and t.tenant_id = #{scopedTenantId}
and t.order_status = #{orderStatus}
and t.trace_no = #{traceNo}
and te.in_hospital_code like concat('%', #{inHospitalCode}, '%')
and ( m.code like concat('%', #{materialKeyword}, '%') or m.name like concat('%', #{materialKeyword}, '%') or m.referred_name like concat('%', #{materialKeyword}, '%') or te.material_name like concat('%', #{materialKeyword}, '%') )
and ( m.speci like concat('%', #{materialSpeci}, '%') or te.specification like concat('%', #{materialSpeci}, '%') )
and m.factory_id = #{factoryId}
and coalesce(te.supplier_id, gdi.supplier_id, m.supplier_id) = #{supplierId}
and ( fs.code like concat('%', #{supplierKeyword}, '%') or fs.name like concat('%', #{supplierKeyword}, '%') or fs.referred_code like concat('%', #{supplierKeyword}, '%') or te.supplier like concat('%', #{supplierKeyword}, '%') )
and (gdep.warehouse_id = #{warehouseId} or wh_src.id = #{warehouseId})
and te.batch_no = #{batchNo}
and gdi.material_no like concat('%', #{materialNo}, '%')
and ( coalesce(hci.item_code, m.his_charge_item_id) like concat('%', #{chargeCodeKeyword}, '%') or m.his_charge_item_id like concat('%', #{chargeCodeKeyword}, '%') )
and t.patient_name like concat('%', #{patientName}, '%') and t.hospital_number like concat('%', #{hospitalNumber}, '%')
and m.udi_no like concat('%', #{udiKeyword}, '%')
and m.sunshine_code like concat('%', #{sunshineCodeKeyword}, '%')
and m.medical_no like concat('%', #{medicalNoKeyword}, '%')
and m.is_billing = #{isBilling} and m.is_procure = #{isProcure} and m.is_monitor = #{isMonitor} and t.apply_dept_id = #{applyDeptId} and t.exec_dept_id = #{execDeptId} and date(t.create_time) >= #{startDate} and date(t.create_time) <= #{endDate} order by t.create_time desc, te.id desc

select x.department_id as departmentId, x.department_name as departmentName, x.material_id as materialId, x.material_name as materialName, x.specification as specification, x.model as model, x.unit_name as unitName, sum(x.consume_qty) as consumeQty, sum(x.remain_qty) as remainQty from ( select t.exec_dept_id as department_id, d.name as department_name, te.material_id as material_id, coalesce(m.name, te.material_name) as material_name, coalesce(m.speci, te.specification) as specification, coalesce(m.model, te.model) as model, coalesce(fu.unit_name, te.unit) as unit_name, ifnull(te.quantity, 0) as consume_qty, 0 as remain_qty from gz_traceability_entry te inner join gz_traceability t on te.parent_id = t.id and t.del_flag = '0' left join fd_department d on d.id = t.exec_dept_id left join fd_material m on m.id = te.material_id left join fd_unit fu on fu.unit_id = m.unit_id left join gz_dep_inventory gdi on gdi.id = te.inventory_id and gdi.del_flag != 1 where te.del_flag = '0' and t.tenant_id = #{scopedTenantId} and t.exec_dept_id is not null and t.order_status = 2 and t.exec_dept_id = #{departmentId} and te.material_id = #{materialId}
and (m.name like concat('%', #{materialName}, '%') or te.material_name like concat('%', #{materialName}, '%'))
and te.supplier_id = #{supplierId} and te.batch_no = #{batchNo} and gdi.material_no = #{materialNo} and date(t.audit_date) >= #{beginDate} and date(t.audit_date) <= #{endDate}
union all
select gdi.department_id as department_id, d.name as department_name, gdi.material_id as material_id, m.name as material_name, m.speci as specification, m.model as model, fu.unit_name as unit_name, 0 as consume_qty, ifnull(gdi.qty, 0) as remain_qty from gz_dep_inventory gdi left join fd_department d on d.id = gdi.department_id left join fd_material m on m.id = gdi.material_id left join fd_unit fu on fu.unit_id = m.unit_id where gdi.del_flag != 1 and gdi.tenant_id = #{scopedTenantId} and gdi.department_id is not null and ifnull(gdi.qty, 0) > 0 and gdi.department_id = #{departmentId} and gdi.material_id = #{materialId}
and m.name like concat('%', #{materialName}, '%')
and gdi.supplier_id = #{supplierId} and gdi.batch_no = #{batchNo} and gdi.material_no = #{materialNo} and date(gdi.warehouse_date) >= #{beginDate} and date(gdi.warehouse_date) <= #{endDate} ) x group by x.department_id, x.department_name, x.material_id, x.material_name, x.specification, x.model, x.unit_name having sum(x.consume_qty) > 0 or sum(x.remain_qty) > 0 order by x.department_name, x.material_name
